      boolean isDeletedOk = blockStoreFile.delete();
      log.debug("Deleting SPV block store (pass 1) from file:\n'{}'", blockStoreFile.getAbsolutePath());
      log.debug("isWritable: '{}' isDeletedOK: '{}'", isWritable, isDeletedOk);
    }
    return true;

  } else {
    return false;
  }
}

