@SuppressFBWarnings("EI_EXPOSE_REP2")
public DLNAThumbnail(byte[] bytes, int width, int height, ImageFormat format, boolean copy) {
	if (copy && bytes != null) {
		this.bytes = new byte[bytes.length];
		System.arraycopy(bytes, 0, this.bytes, 0, bytes.length);
	} else {
		this.bytes = bytes;
	}
	this.width = width;
	this.height = height;
	this.format = format;
}

