@SuppressFBWarnings("EI_EXPOSE_REP2")
public Image(byte[] bytes, ImageInfo imageInfo, boolean copy) {
	if (copy && bytes != null) {
		this.bytes = new byte[bytes.length];
		System.arraycopy(bytes, 0, this.bytes, 0, bytes.length);
	} else {
		this.bytes = bytes;
	}
	if (imageInfo.getMetadata() == null || copy) {
		Metadata metadata;
		try {
			metadata = ImagesUtil.getMetadata(this.bytes, imageInfo.getFormat());
		} catch (ImageProcessingException | IOException e) {
			LOGGER.error("Error reading image metadata: {}", e.getMessage());
			LOGGER.trace("", e);
			metadata = new Metadata();
		}
		imageInfo = imageInfo.copy(metadata);
	}
	this.imageInfo = imageInfo;
}

@SuppressFBWarnings("EI_EXPOSE_REP2")
public Image(
	byte[] bytes,
	int width,
	int height,
	ImageFormat format,
	ColorModel colorModel,
	Metadata metadata,
	boolean imageIOSupport,
	boolean copy
) {
	if (copy && bytes != null) {
		this.bytes = new byte[bytes.length];
		System.arraycopy(bytes, 0, this.bytes, 0, bytes.length);
	} else {
		this.bytes = bytes;
	}
	if (metadata == null || copy) {
		try {
			metadata = ImagesUtil.getMetadata(this.bytes, format);
		} catch (ImageProcessingException | IOException e) {
			LOGGER.error("Error reading image metadata: {}", e.getMessage());
			LOGGER.trace("", e);
			metadata = new Metadata();
		}
	}
	this.imageInfo = new ImageInfo(
		width,
		height,
		format,
		bytes != null ? bytes.length : 0,
		colorModel,
		metadata,
		imageIOSupport
	);
}

