public Object getDynamic(String token, StaplerRequest req, StaplerResponse rsp) {
    for (Action a : getAllActions()) {
        if(a==null)
            continue;   // be defensive
        String urlName = a.getUrlName();
        if(urlName==null)
            continue;
        if(urlName.equals(token))
            return a;
    }
    return null;
}

