                old.add(a1);
            }
        } else if (clazz.isInstance(a1) && !a.equals(a1)) {
            old.add(a1);
        }
    }
    current.removeAll(old);
    if (!found) {
        addAction(a);
    }
    return !(old.isEmpty() && found);
