        case CURRENT_ROW:
            frameEndRows = 0;
        case FOLLOWING:
            break;
        case UNBOUNDED_PRECEDING:
            // This is an error
        default:
            break;
    }
    this.frameEnd = new FrameType(frameEnd, frameEndRows);
}

