                                   DescriptorSerializer serializer,
                                   byte[] bytes,int offset,int length,boolean desc){
    this.bytes = bytes;
    this.offset = offset;
    this.length = length;
    if (dvd != null) {
        ((NullValueData)dvd).setIsNull(true);
    }

    deserialized=false;
    this.descendingOrder=desc;
    this.serializer=serializer;
    this.tableVersion=tableVersion;
    isNull = evaluateNull();
}

