public static String HEX(String s) throws UnsupportedEncodingException {
    if (s == null)
        return null;
    else {
        byte[] b = s.getBytes(Bytes.UTF8_CHARSET);
        return StringUtil.toHexString(b, 0, b.length).toUpperCase();
    }
}

