a_post_commit:
@SuppressFBWarnings(value="DM_GC", justification = "Intentional")
public String buildRuntimeInfo(LocalizedResource locallangUtil)
{

    StringBuilder s = new StringBuilder(locallangUtil.getTextMessage("DRDA_RuntimeInfoBanner.I") + "\n");
    int sessionCount = 0;
    s.append(locallangUtil.getTextMessage("DRDA_RuntimeInfoSessionBanner.I")).append("\n");
    for (int i = 0; i < threadList.size(); i++)
    {
        String sessionInfo  = ((DRDAConnThread)
                               threadList.get(i)).buildRuntimeInfo("",locallangUtil) ;
        if (!sessionInfo.isEmpty())
        {
            sessionCount ++;
            s.append(sessionInfo).append("\n");
        }
    }
    int waitingSessions = 0;
    for (int i = 0; i < runQueue.size(); i++)
    {
            s.append(((Session) runQueue.get(i)).buildRuntimeInfo("", locallangUtil));
            waitingSessions ++;
    }
    s.append("-------------------------------------------------------------\n");
    s.append(locallangUtil.getTextMessage("DRDA_RuntimeInfoNumThreads.I")).append(threadList.size()).append("\n");
    s.append(locallangUtil.getTextMessage("DRDA_RuntimeInfoNumActiveSessions.I")).append(sessionCount).append("\n");
    s.append(locallangUtil.getTextMessage("DRDA_RuntimeInfoNumWaitingSessions.I")).append(+waitingSessions).append("\n\n");

    Runtime rt = Runtime.getRuntime();
    rt.gc();
    long totalmem = rt.totalMemory();
    long freemem = rt.freeMemory();
    s.append(locallangUtil.getTextMessage("DRDA_RuntimeInfoTotalMemory.I")).append(+totalmem).append("\t");
    s.append(locallangUtil.getTextMessage("DRDA_RuntimeInfoFreeMemory.I")).append(+freemem).append("\n\n");

    return s.toString();
}

