                    ForeignKeyConstraintDescriptor foreignKeyConstraintDescriptor = (ForeignKeyConstraintDescriptor) cd;
                    ConstraintDescriptor referencedCd = foreignKeyConstraintDescriptor.getReferencedConstraint();
